'use server';
import {z} from "zod";
import { revalidatePath }  from "next/cache";
import {redirect} from "next/navigation";
import postgres from "postgres";

const FormDataSchema = z.object({
  id: z.string(),
  customerId: z.string(),
  amount: z.coerce.number(),
  status: z.string(),
  date: z.string()
});

const CreateInvoice = FormDataSchema.omit({ id: true, date: true });

const sql = postgres(process.env.POSTGRES_URL!, {
  ssl: 'require'
});
export async function createInvoice(data: FormData) {
  const {customerId, amount, status} = CreateInvoice.parse({
    customerId: data.get("customerId"),
    amount: data.get("amount"),
    status: data.get('status')
  });

  const amountInCents = amount * 100;
  const date = new Date().toISOString().split("T")[0];
  


  // Here you would typically call your database or an external API to create the invoice
  console.log("Creating invoice with:");

  await sql`
    INSERT INTO invoices (customer_id, amount, status, date)
    VALUES (${customerId}, ${amountInCents}, ${status}, ${date})
  `;

  revalidatePath("/dashboard/invoices");
  redirect("/dashboard/invoices");
} 